import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyStat {
  day: string;
  reviews: number;
}

interface WidgetData {
  pendingReviews: number;
  averageReviewTime: string;
  weeklyStats: WeeklyStat[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { pendingReviews, averageReviewTime, weeklyStats } = widgetData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#2C3E50' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Pending Reviews
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#E74C3C' }}>
              {pendingReviews}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Avg Review Time: {averageReviewTime}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              series={[
                {
                  data: weeklyStats.map(stat => stat.reviews),
                  color: '#E74C3C',
                },
              ]}
              xAxis={[
                {
                  data: weeklyStats.map(stat => stat.day),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#ECF0F1',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
